fn main() {
    let v = vec![1, 2, 3, 4, 5];
    let mut sum = 0;
    for &n in &v {
        sum += n;
    }
    println!("sum: {}", sum);
    println!("v still exists: {:?}", v);
}

fn main() {
    let mut v = vec![1, 2, 3];
    v.push(4);
    v.push(5);
    println!("{:?}", v);
    while let Some(x) = v.pop() {
        print!("{} ", x);
    }
    println!();
}

fn main() {
    let nums = vec![1, 2, 3, 4, 5, 6, 7, 8];
    let evens_doubled: Vec<i32> = nums.iter()
        .filter(|&&x| x % 2 == 0)
        .map(|&x| x * 2)
        .collect();
    println!("{:?}", evens_doubled);
}

fn main() {
    let mut v = vec![3, 1, 4, 1, 5, 9, 2, 6, 5, 3];
    v.sort();
    v.dedup();
    println!("{:?}", v);
}

fn main() {
    let v = vec![10, 20, 30];
    println!("len: {}", v.len());
    println!("empty: {}", v.is_empty());
    println!("has 20: {}", v.contains(&20));
    println!("sum: {}", v.iter().sum::<i32>());
}

#[derive(Debug)]
struct Student {
    name: String,
    grade: u32,
}

fn main() {
    let mut class = Vec::new();
    class.push(Student { name: String::from("Alice"), grade: 92 });
    class.push(Student { name: String::from("Bob"),   grade: 85 });
    class.push(Student { name: String::from("Carol"), grade: 97 });
    class.sort_by_key(|s| s.grade);
    for s in &class {
        println!("{}: {}", s.name, s.grade);
    }
}
